export type EkitIconName = keyof typeof EKIT_GLYPHS;

export function EkitIcon({ name, className, size, style }: { name: EkitIconName; className?: string; size?: number; style?: React.CSSProperties }) {
  const glyph = EKIT_GLYPHS[name];
  if (!glyph) return null;
  return (
    <svg viewBox={`0 0 ${glyph.adv} 1024`} className={className} style={size ? { width: size, height: size, ...style } : style} fill="currentColor" aria-hidden>
      <path d={glyph.d} />
    </svg>
  );
}